<?php namespace App\Repositories\Transport;use App\Repositories\BaseRepository;use App\Models\Transport\TransportRoute;use Illuminate\Database\Eloquent\Collection;class TransportRouteRepository extends BaseRepository{    public function __construct(TransportRoute $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByName(string $name): ?TransportRoute    {        return $this->query()->where('name', $name)->first();    }    public function findByRouteNo(string $routeNo): ?TransportRoute    {        return $this->query()->where('route_no', $routeNo)->first();    }    public function getActiveRoutes(): Collection    {        return $this->query()->where('is_active', true)->get();    }    public function getByVehicle(int $vehicleId): Collection    {        return $this->findByField('vehicle_id', $vehicleId);    }    public function searchRoutes(string $keyword): Collection    {        return $this->query()->where('name', 'like', "%{$keyword}%")->orWhere('route_no', 'like', "%{$keyword}%")->orWhere('start_point', 'like', "%{$keyword}%")->orWhere('end_point', 'like', "%{$keyword}%")->get();    }    public function getRouteWithAllocations(int $routeId): ?TransportRoute    {        return $this->query()->with('allocations')->findOrFail($routeId);    }    public function getByDriver(int $driverId): Collection    {        return $this->findByField('driver_id', $driverId);    }    public function countStudentsByRoute(): Collection    {        return $this->query()->withCount('allocations')->get();    }}